from fastapi import FastAPI

app = FastAPI()

@app.get('/')
def root():
	return {'status': 'ok'}

@app.get('/items')
def get_items(limit: int = 10, offset: int = 0):
	return {
		'limit': limit,
		'offset': offset
	}
